// Split the folded 'Subject: X\n\n<body>' back into subject + body for the email send.
const r = $('Loop').item.json;
const raw = r.body || '';
let subject = '(no subject)'; let body = raw;
const m = raw.match(/^Subject:\s*(.+?)\n\n([\s\S]*)$/);
if (m) { subject = m[1].trim(); body = m[2]; }
return [{ json: { outreach_id: r.id, lead_id: r.lead_id, step: r.sequence_step, to: r.founder_email, subject, body } }];
